module bubble_sort(input [7:0] a,  
                   input [7:0] b,  
                   input [7:0] c,  
                   input [7:0] d,  
                   input [7:0] e,  
                   output reg [7:0] out1,  
                   output reg [7:0] out2,  
                   output reg [7:0] out3,  
                   output reg [7:0] out4,  
                   output reg [7:0] out5);  

    reg [7:0] obf_arr [0:4];  
    integer i, j;  

    always @(*) begin  
        obf_arr[0] = a;  
        obf_arr[1] = b;  
        obf_arr[2] = c;  
        obf_arr[3] = d;  
        obf_arr[4] = e;  

        for (i = 0; i < 4; i = i + 1) begin  
            for (j = 0; j < 4 - i; j = j + 1) begin  
                if (obf_arr[j] > obf_arr[j + 1]) begin  
                    {obf_arr[j], obf_arr[j + 1]} = {obf_arr[j + 1], obf_arr[j]};  
                end  
            end  
        end  

        out1 = obf_arr[0];  
        out2 = obf_arr[1];  
        out3 = obf_arr[2];  
        out4 = obf_arr[3];  
        out5 = obf_arr[4];  
    end  
endmodule
